#include <iostream>
#include <Eigen/Core>
#include <unsupported/Eigen/Splines>

using namespace std;
using namespace Eigen;

int main()
{
    // Define your x and y data points
    ArrayXd x(5);
    ArrayXd y(5);
    x << 1, 2, 3, 4, 5;
    y << 2, 1, 0, 1, 2;

    // Define the number of control points and the degree of the B-spline curve
    int n_control_points = 4;
    int degree = 3;

    // Generate the knot vector using the Uniform parameterization method
    VectorXd knots = VectorXd::LinSpaced(n_control_points + degree + 1, x[0], x[x.size() - 1]);

    // Fit the B-spline curve to the data points
    SplineFitting<Spline<double, degree, 1>> fitting;
    Spline<double, degree, 1> spline = fitting.Interpolate(y, knots, x);

    // Evaluate the B-spline curve at new points
    int n_eval_points = 100;
    ArrayXd x_new = ArrayXd::LinSpaced(n_eval_points, x[0], x[x.size() - 1]);
    ArrayXd y_new(n_eval_points);
    for (int i = 0; i < n_eval_points; i++) {
        y_new(i) = spline(x_new(i));
    }

    // Print the original data points and the fitted curve
    cout << "Original data points:" << endl << x.transpose() << endl << y.transpose() << endl;
    cout << "Fitted B-spline curve:" << endl << x_new.transpose() << endl << y_new.transpose() << endl;

    return 0;
}
```

